         let disabled = HostcallSuperinstructionCompiler::new(false, 2, 3);
         assert!(!disabled.enabled());
     }
+
+    // ── Property tests ──
+
+    mod proptest_superinstructions {
+        use super::*;
+        use proptest::prelude::*;
+
+        fn arb_opcode() -> impl Strategy<Value = String> {
+            prop::sample::select(vec![
+                "session.get_state".to_string(),
+                "session.get_messages".to_string(),
+                "events.list".to_string(),
+                "events.emit".to_string(),
+                "tool.read".to_string(),
+                "tool.write".to_string(),
+                "events.get_model".to_string(),
+                "session.set_label".to_string(),
+            ])
+        }
+
+        fn arb_trace() -> impl Strategy<Value = Vec<String>> {
+            prop::collection::vec(arb_opcode(), 0..6)
+        }
+
+        fn arb_compiler() -> impl Strategy<Value = HostcallSuperinstructionCompiler> {
+            (2..8u32, 2..6usize).prop_map(|(min_support, max_window)| {
+                HostcallSuperinstructionCompiler::new(true, min_support, max_window)
+            })
+        }
+
+        proptest! {
+            #[test]
+            fn compile_plans_is_deterministic(
+                compiler in arb_compiler(),
+                traces in prop::collection::vec(arb_trace(), 0..8),
+            ) {
+                let plans1 = compiler.compile_plans(&traces);
+                let plans2 = compiler.compile_plans(&traces);
+                assert!(plans1 == plans2, "compile_plans must be deterministic");
+            }
+
+            #[test]
+            fn all_plans_have_positive_cost_delta(
+                compiler in arb_compiler(),
+                traces in prop::collection::vec(arb_trace(), 1..8),
+            ) {
+                let plans = compiler.compile_plans(&traces);
+                for plan in &plans {
+                    assert!(
+                        plan.expected_cost_delta > 0,
+                        "plan {} has non-positive delta {}",
+                        plan.plan_id,
+                        plan.expected_cost_delta,
+                    );
+                }
+            }
+
+            #[test]
+            fn plans_sorted_by_cost_delta_descending(
+                compiler in arb_compiler(),
+                traces in prop::collection::vec(arb_trace(), 1..8),
+            ) {
+                let plans = compiler.compile_plans(&traces);
+                for pair in plans.windows(2) {
+                    assert!(
+                        pair[0].expected_cost_delta >= pair[1].expected_cost_delta,
+                        "plans must be sorted by cost delta descending: {} vs {}",
+                        pair[0].expected_cost_delta,
+                        pair[1].expected_cost_delta,
+                    );
+                }
+            }
+
+            #[test]
+            fn cost_delta_equals_baseline_minus_fused(
+                width in 2..64usize,
+            ) {
+                let baseline = estimated_baseline_cost(width);
+                let fused = estimated_fused_cost(width);
+                let delta = baseline.saturating_sub(fused);
+                assert!(
+                    delta > 0,
+                    "fused cost must be less than baseline for width {width}"
+                );
+                assert!(
+                    delta == baseline - fused,
+                    "delta must equal baseline - fused"
+                );
+            }
+
+            #[test]
+            fn fused_cost_strictly_less_than_baseline_for_width_ge_2(
+                width in 2..1000usize,
+            ) {
+                let baseline = estimated_baseline_cost(width);
+                let fused = estimated_fused_cost(width);
+                assert!(
+                    fused < baseline,
+                    "fused ({fused}) must be < baseline ({baseline}) at width {width}"
+                );
+            }
+
+            #[test]
+            fn opcode_window_signature_is_deterministic(
+                window in prop::collection::vec(arb_opcode(), 1..6),
+            ) {
+                let sig1 = opcode_window_signature(&window);
+                let sig2 = opcode_window_signature(&window);
+                assert!(sig1 == sig2, "signature must be deterministic");
+                assert!(sig1.len() == 16, "signature must be 16 hex chars");
+            }
+
+            #[test]
+            fn disabled_compiler_always_returns_empty(
+                min_support in 1..10u32,
+                max_window in 2..8usize,
+                traces in prop::collection::vec(arb_trace(), 0..8),
+            ) {
+                let compiler = HostcallSuperinstructionCompiler::new(false, min_support, max_window);
+                let plans = compiler.compile_plans(&traces);
+                assert!(plans.is_empty(), "disabled compiler must return no plans");
+            }
+
+            #[test]
+            fn plan_width_never_exceeds_max_window(
+                compiler in arb_compiler(),
+                traces in prop::collection::vec(arb_trace(), 1..8),
+            ) {
+                let plans = compiler.compile_plans(&traces);
+                for plan in &plans {
+                    assert!(
+                        plan.width() <= compiler.max_window(),
+                        "plan width {} exceeds max_window {}",
+                        plan.width(),
+                        compiler.max_window(),
+                    );
+                }
+            }
+
+            #[test]
+            fn plan_support_count_meets_min_support(
+                compiler in arb_compiler(),
+                traces in prop::collection::vec(arb_trace(), 1..10),
+            ) {
+                let plans = compiler.compile_plans(&traces);
+                for plan in &plans {
+                    assert!(
+                        plan.support_count >= compiler.min_support(),
+                        "plan {} has support {} < min_support {}",
+                        plan.plan_id,
+                        plan.support_count,
+                        compiler.min_support(),
+                    );
+                }
+            }
+        }
+    }
 }

@@ -1060,4 +1060,204 @@ mod tests {
         assert!(r2.jit_hit);
         assert_eq!(jit.telemetry().jit_hits, 2);
     }
+
+    // ── Property tests ──
+
+    mod proptest_trace_jit {
+        use super::*;
+
+        use proptest::prelude::*;
+
+        fn arb_opcode() -> impl Strategy<Value = String> {
+            prop::sample::select(vec![
+                "session.get_state".to_string(),
+                "session.get_messages".to_string(),
+                "events.list".to_string(),
+                "tool.read".to_string(),
+                "tool.write".to_string(),
+                "events.emit".to_string(),
+            ])
+        }
+
+        fn arb_window() -> impl Strategy<Value = Vec<String>> {
+            prop::collection::vec(arb_opcode(), 2..6)
+        }
+
+        fn arb_plan() -> impl Strategy<Value = HostcallSuperinstructionPlan> {
+            (arb_window(), 2..100u32).prop_map(|(window, support)| {
+                let width = window.len();
+                let baseline = i64::try_from(width).unwrap_or(0) * 10;
+                let fused = 6 + i64::try_from(width).unwrap_or(0) * 2;
+                HostcallSuperinstructionPlan {
+                    schema: HOSTCALL_SUPERINSTRUCTION_SCHEMA_VERSION.to_string(),
+                    version: HOSTCALL_SUPERINSTRUCTION_PLAN_VERSION,
+                    plan_id: format!("arb_{width}_{support}"),
+                    trace_signature: format!("sig_arb_{width}_{support}"),
+                    opcode_window: window,
+                    support_count: support,
+                    estimated_cost_baseline: baseline,
+                    estimated_cost_fused: fused,
+                    expected_cost_delta: baseline - fused,
+                }
+            })
+        }
+
+        fn arb_guard_context() -> impl Strategy<Value = GuardContext> {
+            (any::<bool>(), 0..200u32).prop_map(|(vetoing, support)| GuardContext {
+                safety_envelope_vetoing: vetoing,
+                current_support_count: support,
+            })
+        }
+
+        fn arb_config() -> impl Strategy<Value = TraceJitConfig> {
+            (1..16u64, 2..32usize, 1..8u64).prop_map(
+                |(min_exec, max_traces, max_failures)| {
+                    TraceJitConfig::new(true, min_exec, max_traces, max_failures)
+                },
+            )
+        }
+
+        proptest! {
+            #[test]
+            fn jit_cost_less_than_fused_for_width_ge_2(width in 2..1000usize) {
+                let jit_cost = estimated_jit_cost(width);
+                let fused_cost = 6 + i64::try_from(width).unwrap() * 2;
+                assert!(
+                    jit_cost < fused_cost,
+                    "JIT cost ({jit_cost}) must be < fused cost ({fused_cost}) at width {width}"
+                );
+            }
+
+            #[test]
+            fn compiled_trace_tier_improvement_nonnegative(plan in arb_plan()) {
+                let compiled = CompiledTrace::from_plan(&plan);
+                assert!(
+                    compiled.tier_improvement_delta >= 0,
+                    "tier_improvement_delta must be non-negative, got {}",
+                    compiled.tier_improvement_delta,
+                );
+            }
+
+            #[test]
+            fn compiled_trace_always_has_three_guards(plan in arb_plan()) {
+                let compiled = CompiledTrace::from_plan(&plan);
+                assert!(
+                    compiled.guards.len() == 3,
+                    "compiled trace must have 3 guards (OpcodePrefix, SafetyEnvelope, MinSupport)"
+                );
+            }
+
+            #[test]
+            fn compiled_trace_width_matches_plan(plan in arb_plan()) {
+                let compiled = CompiledTrace::from_plan(&plan);
+                assert!(
+                    compiled.width == plan.width(),
+                    "compiled width {} != plan width {}",
+                    compiled.width,
+                    plan.width(),
+                );
+            }
+
+            #[test]
+            fn disabled_jit_never_promotes(
+                plan in arb_plan(),
+                executions in 1..50usize,
+            ) {
+                let config = TraceJitConfig::new(false, 1, 64, 4);
+                let mut jit = TraceJitCompiler::new(config);
+                for _ in 0..executions {
+                    let promoted = jit.record_plan_execution(&plan);
+                    assert!(!promoted, "disabled JIT must never promote");
+                }
+                assert!(
+                    jit.cache_size() == 0,
+                    "disabled JIT must have empty cache"
+                );
+            }
+
+            #[test]
+            fn cache_size_never_exceeds_max(
+                config in arb_config(),
+                plans in prop::collection::vec(arb_plan(), 1..20),
+            ) {
+                let max = config.max_compiled_traces;
+                let min_exec = config.min_jit_executions;
+                let mut jit = TraceJitCompiler::new(config);
+                for plan in &plans {
+                    for _ in 0..min_exec {
+                        jit.record_plan_execution(plan);
+                    }
+                }
+                assert!(
+                    jit.cache_size() <= max,
+                    "cache size {} exceeds max {}",
+                    jit.cache_size(),
+                    max,
+                );
+            }
+
+            #[test]
+            fn telemetry_traces_compiled_matches_cache_plus_evictions(
+                config in arb_config(),
+                plans in prop::collection::vec(arb_plan(), 1..10),
+            ) {
+                let min_exec = config.min_jit_executions;
+                let mut jit = TraceJitCompiler::new(config);
+                for plan in &plans {
+                    for _ in 0..min_exec {
+                        jit.record_plan_execution(plan);
+                    }
+                }
+                let t = jit.telemetry();
+                // compiled = currently cached + evicted + invalidated
+                assert!(
+                    t.traces_compiled >= t.cache_size,
+                    "traces_compiled ({}) must be >= cache_size ({})",
+                    t.traces_compiled,
+                    t.cache_size,
+                );
+            }
+
+            #[test]
+            fn guard_check_is_deterministic(
+                plan in arb_plan(),
+                trace_opcodes in arb_window(),
+                ctx in arb_guard_context(),
+            ) {
+                let compiled = CompiledTrace::from_plan(&plan);
+                let r1 = compiled.guards_pass(&trace_opcodes, &ctx);
+                let r2 = compiled.guards_pass(&trace_opcodes, &ctx);
+                assert!(r1 == r2, "guard check must be deterministic");
+            }
+
+            #[test]
+            fn jit_hit_implies_zero_deopt_reason(
+                config in arb_config(),
+                plan in arb_plan(),
+            ) {
+                let min_exec = config.min_jit_executions;
+                let mut jit = TraceJitCompiler::new(config);
+                // Promote the plan
+                for _ in 0..min_exec {
+                    jit.record_plan_execution(&plan);
+                }
